FormScriptItem.Script:
//FillinAndRelate RRC
var isFormValid = VV.Form.Template.FormValidation();
var title = 'Subscription Pack';
var fields = [
    {
        sourceFieldName: 'Type',
        sourceFieldValue: VV.Form.GetFieldValue('Type'),
        targetFieldName: 'Type',
    },
    {
        sourceFieldName: 'Subscription Pack ID',
        sourceFieldValue: VV.Form.GetFieldValue('Subscription Pack ID'),
        targetFieldName: 'Subscription Pack ID',
    },
];

var GUID = 'c09dff9c-2751-ec11-a9d3-e4a99b52c98f';

function okFunction() {
    VV.Form.ShowLoadingPanel();
    //Call the fill in global script
    VV.Form.DoAjaxFormSave().then(function () {
        VV.Form.HideLoadingPanel();
        VV.Form.Global.FillinAndRelateForm(GUID, fields);
    });
}

var cancelfunction = function () {
    return;
};

if (isFormValid) {
    //Confirmation function
    VV.Form.Global.DisplayConfirmMessaging('Please, confirm if  you want to add a new subscription pack.', title, okFunction, cancelfunction);
} else {
    VV.Form.ShowLoadingPanel();
    VV.Form.HideLoadingPanel();
    VV.Form.Global.DisplayMessaging(
        'All of the fields have not been filled in completely. Highlight your mouse over the red icon to see how you can resolve the error stopping you from saving this form.',
        title
    );
}

//FormValidation for the Subscription pack

//pass in ControlName to validate a single item or nothing to validate everything.
var ErrorReporting = true;
var RunAll = false;
if (ControlName == null) {
    RunAll = true;
}

if (ControlName == 'Subscription Pack Name' || RunAll) {
    if (VV.Form.Global.CentralValidation(VV.Form.GetFieldValue('Subscription Pack Name'), 'Blank') == false) {
        VV.Form.SetValidationErrorMessageOnField('Subscription Pack Name', 'A value needs to be entered for the Subscription Pack Name.');
        ErrorReporting = false;
    }
    else {
        VV.Form.ClearValidationErrorOnField('Subscription Pack Name');
    }
}

if (ControlName == 'Start Date' || RunAll) {
    //if the Start Date is empty
    if (VV.Form.Global.CentralValidation(VV.Form.GetFieldValue('Start Date'), 'Blank') == false) {
        VV.Form.SetValidationErrorMessageOnField('Start Date', 'A date for Start Date has to be selected.')
        ErrorReporting = false;
    }
    //If the start date is not empty
    else {
        VV.Form.ClearValidationErrorOnField('Start Date');
        //if the End Date Date is not Empty 
        if (VV.Form.GetFieldValue('End Date')) {
            if (VV.Form.Global.CentralDateValidation(VV.Form.GetFieldValue('Start Date'), 'DateBefore', VV.Form.GetFieldValue('End Date'), 'D', 1) != true) {
                VV.Form.SetValidationErrorMessageOnField('Start Date', 'A date for Start Date has to be selected being at least one day before End Date.')
                ErrorReporting = false;
            }
            else {
                VV.Form.ClearValidationErrorOnField('End Date')
                VV.Form.ClearValidationErrorOnField('Start Date');
            }
        }
    }
}
if (ControlName == 'End Date' || RunAll) {
    //if the End Date date is empty
    if (VV.Form.Global.CentralValidation(VV.Form.GetFieldValue('End Date'), 'Blank') == false) {
        VV.Form.SetValidationErrorMessageOnField('End Date', 'A date for End Date has to be selected.');
        ErrorReporting = false;
    } else {
        VV.Form.ClearValidationErrorOnField('End Date');
        //If Start Date Date is not Empty

        if (VV.Form.GetFieldValue('Start Date')) {
            if (VV.Form.Global.CentralDateValidation(VV.Form.GetFieldValue('End Date'), 'DateAfter', VV.Form.GetFieldValue('Start Date'), 'D', 1) != true) {
                VV.Form.SetValidationErrorMessageOnField('End Date', 'A date for End Date has to be selected being at least one day after Start Date.');
                ErrorReporting = false;
            }
            else {
                VV.Form.ClearValidationErrorOnField('Start Date')
                VV.Form.ClearValidationErrorOnField('End Date');
            }
        }
    }
}

if (ControlName == 'Status' || RunAll) {
    if (VV.Form.Global.CentralValidation(VV.Form.GetFieldValue('Status').trim(), 'DDSelect') == false) {
        VV.Form.SetValidationErrorMessageOnField('Status', 'Please select a Status option from the dropdown list.');
        ErrorReporting = false;
    }
    else {
        VV.Form.ClearValidationErrorOnField('Status');
    }
}

if (ControlName == 'Type' || RunAll) {
    if (VV.Form.Global.CentralValidation(VV.Form.GetFieldValue('Type').trim(), 'DDSelect') == false) {
        VV.Form.SetValidationErrorMessageOnField('Type', 'Please select a Type option from the dropdown list.');
        ErrorReporting = false;
    }
    else {
        VV.Form.ClearValidationErrorOnField('Type');
    }
}

return ErrorReporting

if (VV.Form.Template.FormValidation() === true) {
    //Confirmation function
    var messageData = 'The record has been saved.';
    var title = 'Save Form';

    VV.Form.ShowLoadingPanel();
    VV.Form.DoAjaxFormSave().then(function (resp) {
        VV.Form.HideLoadingPanel();
        VV.Form.Global.DisplayMessaging(messageData, title);
    });
} else {
    VV.Form.ShowLoadingPanel();
    VV.Form.HideLoadingPanel();
    VV.Form.Global.DisplayMessaging(
        'All of the fields have not been filled in completely or there is an issue with the range of the date entered. Highlight your mouse over the red icon to see how you can resolve the error stopping you from saving this form.', "Subscription Pack"
    );
}

//setting a new date to update the date field in the read only section to be able to save the form each time the add item //button is clicked
var todaydatesave = new Date();
VV.Form.SetFieldValue('DateTimeSave', todaydatesave, true);
VV.Form.DoPostbackSave();
VV.Form.Template.FillinAndRelate();

//CloseButtonFormat hides the VV close button, changes the form close button colors, and makes them clickable even in read-only mode. 
//This function must be called on Load and in EventsEnd.
//VV.Form.Global.CloseButtonFormat();

//btn Deactive
var isFormValid = VV.Form.Template.FormValidation()
var messageData = 'The Subscription Pack has been saved.';
var title = 'Subscription Packs';

if (isFormValid) {
    //Confirmation function

    var okfunction = function () {
        VV.Form.ShowLoadingPanel();

        // Set the status to be ‘Disabled’
        VV.Form.SetFieldValue('Status', 'Inactive', true);

        VV.Form.DoAjaxFormSave().then(function () {
            VV.Form.HideLoadingPanel();
            VV.Form.Global.DisplayMessaging(messageData, title);
        });
    };

    var cancelfunction = function () {
        return;
    }

    VV.Form.Global.DisplayConfirmMessaging('You have indicated that you want to deactivate the Subscription Pack. Select OK to continue or Cancel if you are not yet ready', title, okfunction, cancelfunction);

}
else {
    VV.Form.ShowLoadingPanel();
    VV.Form.HideLoadingPanel()
    VV.Form.Global.DisplayMessaging(
        'The Subscription Pack was not saved. Please, complete the required fields before saving.', title
    );
}

//CloseButtonFormat hides the VV close button, changes the form close button colors, and makes them clickable even in read-only mode. 
//This function must be called on Load and in EventsEnd.
//VV.Form.Global.CloseButtonFormat();

//Tab Control should be set to the first tab on each load.
VV.Form.SetFieldValue('Tab Control', 'Button1');
